// Parse payload
var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { node.warn('Bad JSON: ' + msg.payload); return null; }
}

var component = d.component;
var rssi      = d.rssi_dbm;
var ts        = d.ts;

if (!component || rssi === undefined || !ts) return null;

// Per-component state so multiple sensors don't interfere
var lastRssi = context.get('lastRssi_' + component);  // undefined on first message
var lastTs   = context.get('lastTs_'   + component) || '';

// Update stored state
context.set('lastRssi_' + component, rssi);
context.set('lastTs_'   + component, ts);

// First message for this component — initialise state, no event
if (lastRssi === undefined) {
    return null;
}

var logMsg = null;

if (lastRssi !== 0 && rssi === 0) {
    // Transition home → field: session started
    // ts is the timestamp of the first field reading = actual session start time
    logMsg = JSON.stringify({
        component: component,
        category:  'System',
        message:   'Field session started at ' + ts
    });
} else if (lastRssi === 0 && rssi !== 0) {
    // Transition field → home: session ended
    // lastTs is the timestamp of the last field reading = actual session end time
    logMsg = JSON.stringify({
        component: component,
        category:  'System',
        message:   'Field session ended at ' + lastTs
    });
}

if (logMsg) {
    msg.payload = logMsg;
    msg.topic   = 'jctsh/components/' + component + '/log';
    return msg;
}

return null;
